import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import { handleError, handleSuccess } from "../utils";
import { ToastContainer } from "react-toastify";
import "./home.css";

function Home() {
    const [loggedInUser, setLoggedInUser] = useState("");
    const [userProfile, setUserProfile] = useState(null);
    const navigate = useNavigate();

    useEffect(() => {
        const username = localStorage.getItem("loggedInUser");
        const userId = localStorage.getItem("userId");  // Get the user ID from localStorage

        console.log("username from localStorage:", username); // Log for debugging
        console.log("userId from localStorage:", userId); // Log for debugging

        setLoggedInUser(username || "Utilisateur");

        if (!userId) {
            handleError("User ID not found, please log in again.");
            navigate("/login");
        } else {
            console.log("Fetching user profile for userId:", userId); // Log for debugging
            fetchUserProfileById(userId);  // Fetch profile by userId
        }
    }, [navigate]);

    const fetchUserProfileById = async (userId) => {
        try {
            const token = localStorage.getItem("token");
            if (!token) {
                handleError("Token not found, please log in again.");
                navigate("/login");
                return;
            }

            // Call the API to fetch the user profile by ID
            const response = await axios.get(`http://localhost:5001/users/${userId}`, {
                headers: { Authorization: `Bearer ${token}` },
            });

            // Check if the API response is successful
            if (response.data.success) {
                setUserProfile(response.data.user);
            } else {
                handleError("User not found");
            }
        } catch (error) {
            console.error("API Error:", error.response?.data || error.message);
            handleError("Failed to fetch user profile");
        }
    };

    const handleLogout = () => {
        // User logout logic
        localStorage.removeItem("token");
        localStorage.removeItem("loggedInUser");
        localStorage.removeItem("userId");  // Remove user ID as well
        handleSuccess("User Logged out");
        setTimeout(() => {
            navigate("/login");
        }, 1000);
    };

    return (
        <div className="home-container">
            <div className="sidebar">
                <h2>Dashboard</h2>
                <ul>
                    <li><a href="/home">Home</a></li>
                    <li><a href="/profile">Profile</a></li>
                    <li><a href="/products">Products</a></li>
                </ul>
            </div>

            <div className="main-content">
                <div className="header">
                    <h1>Welcome, {loggedInUser}</h1>
                    <button onClick={handleLogout} className="logout-btn">Logout</button>
                </div>

                {userProfile ? (
                    <div className="profile-card">
                        <div className="profile-header">
                            <img 
                                src={userProfile.profilePicture || "default-avatar.png"} 
                                alt="Profile" 
                                className="profile-picture" 
                            />
                            <h3>{userProfile.name}</h3>
                            <p className="profile-email">{userProfile.email}</p>
                        </div>
                        <div className="profile-body">
                            <p><strong>Role:</strong> {userProfile.role}</p>
                            <button className="update-profile-btn">Update Profile</button>
                        </div>
                    </div>
                ) : (
                    <p>Loading profile...</p>
                )}

                <ToastContainer />
            </div>
        </div>
    );
}

export default Home;
